// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { Paper, Typography, Grid, Card, CardContent, Table, TableHead, TableBody, TableRow, TableCell, Button, IconButton, CircularProgress, Tooltip } from "@mui/material";
import { getOverview, getUsers, getRiders, getApprovedCaptains, getPendingCaptains, getRides, approveCaptain, rejectCaptain } from "../../services/adminApi";
import { Visibility, Download } from "@mui/icons-material";

export default function AdminDashboard() {
  const [loading, setLoading] = useState(true);
  const [overview, setOverview] = useState({});
  const [currentTab, setCurrentTab] = useState("overview"); // 'users', 'riders', 'captains', 'pendingCaptains', 'rides'
  const [data, setData] = useState([]);

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      if (res.data.success) setOverview(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchData = async (tab) => {
    setLoading(true);
    try {
      let res;
      if (tab === "users") res = await getUsers();
      else if (tab === "riders") res = await getRiders();
      else if (tab === "captains") res = await getApprovedCaptains();
      else if (tab === "pendingCaptains") res = await getPendingCaptains();
      else if (tab === "rides") res = await getRides();
      setData(res.data.users || res.data.riders || res.data.captains || res.data.pendingCaptains || res.data.rides || []);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOverview();
    fetchData("users");
  }, []);

  const handleTabClick = (tab) => {
    setCurrentTab(tab);
    fetchData(tab);
  };

  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData("pendingCaptains");
      fetchData("captains");
      fetchOverview();
    } catch (err) {
      console.error(err);
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData("pendingCaptains");
      fetchOverview();
    } catch (err) {
      console.error(err);
    }
  };

  const renderTable = () => {
    if (loading) return <CircularProgress />;

    if (data.length === 0) return <Typography>No data found.</Typography>;

    const columns = {
      users: ["Full Name", "Email", "Mobile", "Role", "Login Count", "Approval Status"],
      riders: ["Full Name", "Email", "Mobile", "Role", "Login Count", "Approval Status"],
      captains: ["Full Name", "Email", "Mobile", "Role", "Login Count", "Approval Status", "Documents"],
      pendingCaptains: ["Full Name", "Email", "Mobile", "Role", "Login Count", "Approval Status", "Actions", "Documents"],
      rides: ["Rider", "Captain", "Pickup", "Drop", "Fare", "Status"]
    };

    return (
      <Table>
        <TableHead>
          <TableRow>
            {columns[currentTab].map((col) => (
              <TableCell key={col}>{col}</TableCell>
            ))}
          </TableRow>
        </TableHead>
        <TableBody>
          {data.map((item) => (
            <TableRow key={item._id}>
              <TableCell>{item.fullName || item.riderId?.fullName}</TableCell>
              <TableCell>{item.email || item.riderId?.email}</TableCell>
              <TableCell>{item.mobile || item.riderId?.mobile}</TableCell>
              <TableCell>{item.role || item.captainId?.role}</TableCell>
              <TableCell>{item.loginCount || "-"}</TableCell>
              <TableCell>{item.approvalStatus || item.status}</TableCell>

              {/* Actions for Pending Captains */}
              {currentTab === "pendingCaptains" && (
                <TableCell>
                  <Button variant="contained" color="success" onClick={() => handleApprove(item._id)} sx={{ mr: 1 }}>
                    Approve
                  </Button>
                  <Button variant="contained" color="error" onClick={() => handleReject(item._id)}>
                    Reject
                  </Button>
                </TableCell>
              )}

              {/* Documents */}
              {(currentTab === "captains" || currentTab === "pendingCaptains") && (
                <TableCell>
                  {item.documents && item.documents.length > 0 ? (
                    item.documents.map((doc, idx) => (
                      <div key={idx}>
                        <Tooltip title="View">
                          <IconButton href={doc.url} target="_blank">
                            <Visibility />
                          </IconButton>
                        </Tooltip>
                        <Tooltip title="Download">
                          <IconButton href={doc.url} download>
                            <Download />
                          </IconButton>
                        </Tooltip>
                      </div>
                    ))
                  ) : (
                    "-"
                  )}
                </TableCell>
              )}
            </TableRow>
          ))}
        </TableBody>
      </Table>
    );
  };

  return (
    <div>
      <Typography variant="h4" gutterBottom>Admin Dashboard</Typography>

      <Grid container spacing={2} sx={{ mb: 3 }}>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleTabClick("users")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <Typography>Users</Typography>
              <Typography variant="h5">{overview.users || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleTabClick("riders")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <Typography>Riders</Typography>
              <Typography variant="h5">{overview.riders || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleTabClick("captains")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <Typography>Approved Captains</Typography>
              <Typography variant="h5">{overview.captains || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleTabClick("pendingCaptains")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <Typography>Pending Captains</Typography>
              <Typography variant="h5">{overview.pendingCaptains || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card onClick={() => handleTabClick("rides")} sx={{ cursor: "pointer" }}>
            <CardContent>
              <Typography>Total Rides</Typography>
              <Typography variant="h5">{overview.rides || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Paper sx={{ p: 2 }}>{renderTable()}</Paper>
    </div>
  );
}
